# ANTI-PATTERN: Loading entire match history for every query
class CricketAgentAntiPattern:
    def __init__(self):
        self.match_events = []  # All events ever recorded

    def get_current_score(self):
        # Replays ALL events every time
        runs = 0
        for event in self.match_events:
            if event['type'] == 'run':
                runs += event['value']
        return runs

    def get_wickets_after_over(self, over_num):
        # O(n) scan through entire history
        count = 0
        for event in self.match_events:
            if event['over'] <= over_num and event['type'] == 'wicket':
                count += 1
        return count


# BEST PRACTICE: Hybrid windowing with snapshots
class CricketAgentBestPractice:
    def __init__(self, window_size=10):
        self.recent_events = []  # Last N overs only
        self.snapshots = {}      # Over-end snapshots: {over_num: {'runs': X, 'wickets': Y}}
        self.window_size = window_size
        self.current_state = {'runs': 0, 'wickets': 0, 'current_over': 0}

    def record_event(self, event):
        """Add event and maintain sliding window"""
        self.recent_events.append(event)

        if event['type'] == 'run':
            self.current_state['runs'] += event['value']
        elif event['type'] == 'wicket':
            self.current_state['wickets'] += 1

        # Snapshot at over boundaries
        if event.get('is_over_end'):
            over_num = event['over']
            self.snapshots[over_num] = self.current_state.copy()
            # Trim events beyond window
            cutoff_over = over_num - self.window_size
            self.recent_events = [
                e for e in self.recent_events 
                if e['over'] > cutoff_over
            ]

    def get_current_score(self):
        # O(1) from memory
        return self.current_state['runs']

    def get_state_at_over(self, over_num):
        """Query snapshots for instant historical lookup"""
        if over_num in self.snapshots:
            return self.snapshots[over_num]  # O(1) snapshot
        # Fallback: reconstruct from recent window if within range
        return self._reconstruct_from_window(over_num)

    def _reconstruct_from_window(self, target_over):
        """Only replay recent events, not entire history"""
        state = {'runs': 0, 'wickets': 0}
        for event in self.recent_events:
            if event['over'] > target_over:
                break
            if event['type'] == 'run':
                state['runs'] += event['value']
            elif event['type'] == 'wicket':
                state['wickets'] += 1
        return state
